224: // removeTerminatedPods manually removes terminated Deployment pods,
225: // until the deployment is complete
226: func (d *deploymentTester) removeTerminatedPods(ctx context.Context, wg *sync.WaitGroup) {
227: 	defer wg.Done()
228: 
229: 	err := wait.PollUntilContextTimeout(ctx, pollInterval, pollTimeout, true, func(ctx context.Context) (bool, error) {
230: 		// We're done when the deployment is complete
231: 		if completed, err := d.deploymentComplete(); err != nil {
232: 			return false, err
233: 		} else if completed {
234: 			return true, nil
235: 		}
236: 		// Otherwise, mark remaining pods as ready
237: 		rsList, err := deploymentutil.ListReplicaSets(d.deployment, deploymentutil.RsListFromClient(d.c.AppsV1()))
238: 		if err != nil {
239: 			d.t.Log(err)
240: 			return false, nil
241: 		}
242: 		for _, rs := range rsList {
243: 			if err := d.removeRSPods(ctx, rs, math.MaxInt, true, 0); err != nil {
244: 				d.t.Log(err)
245: 				return false, nil
246: 			}
247: 		}
248: 		return false, nil
249: 	})
250: 	if err != nil {
251: 		d.t.Errorf("failed to remove terminated Deployment pods: %v", err)
252: 	}
253: }
