318: // waitForDeploymentCompleteAndMarkPodsReadyAndRemoveTerminating waits for the Deployment to complete
319: // while marking updated Deployment pods as ready and removes terminated pods at the same time.
320: func (d *deploymentTester) waitForDeploymentCompleteAndMarkPodsReadyAndRemoveTerminated(ctx context.Context) error {
321: 	var wg sync.WaitGroup
322: 
323: 	// Manually mark updated Deployment pods as ready in a separate goroutine
324: 	wg.Add(1)
325: 	go d.markUpdatedPodsReady(&wg)
326: 
327: 	wg.Add(1)
328: 	go d.removeTerminatedPods(ctx, &wg)
329: 
330: 	// Wait for the Deployment status to complete using soft check, while Deployment pods are becoming ready
331: 	err := d.waitForDeploymentComplete()
332: 	if err != nil {
333: 		return fmt.Errorf("failed to wait for Deployment status %s: %w", d.deployment.Name, err)
334: 	}
335: 
336: 	// Wait for goroutine to finish
337: 	wg.Wait()
338: 
339: 	return nil
340: }
